from collections import Counter

def solve(grid):
    H, W = len(grid), len(grid[0])
    flat = [c for row in grid for c in row]
    bg = Counter(flat).most_common(1)[0][0]

    # Find connected components with 8-connectivity per color
    color_positions = {}
    for r in range(H):
        for c in range(W):
            if grid[r][c] != bg:
                col = grid[r][c]
                if col not in color_positions:
                    color_positions[col] = []
                color_positions[col].append((r, c))

    rects = []  # (color, (r0, c0, r1, c1))
    patterns = {}  # color -> 3x3 pattern

    for col, positions in color_positions.items():
        pos_set = set(positions)
        visited = set()
        components = []

        for pos in positions:
            if pos not in visited:
                queue = [pos]
                visited.add(pos)
                comp = []
                while queue:
                    cr, cc = queue.pop(0)
                    comp.append((cr, cc))
                    for dr in [-1, 0, 1]:
                        for dc in [-1, 0, 1]:
                            if dr == 0 and dc == 0:
                                continue
                            nr, nc = cr + dr, cc + dc
                            if (nr, nc) in pos_set and (nr, nc) not in visited:
                                visited.add((nr, nc))
                                queue.append((nr, nc))
                components.append(comp)

        for comp in components:
            crs = [p[0] for p in comp]
            ccs = [p[1] for p in comp]
            min_r, max_r = min(crs), max(crs)
            min_c, max_c = min(ccs), max(ccs)
            h = max_r - min_r + 1
            w = max_c - min_c + 1

            if len(comp) == 25 and h == 5 and w == 5:
                rects.append((col, (min_r, min_c, max_r, max_c)))
            elif h <= 3 and w <= 3:
                pat = []
                for pr in range(min_r, min_r + h):
                    row = []
                    for pc in range(min_c, min_c + w):
                        row.append(grid[pr][pc])
                    pat.append(row)
                # Pad to 3x3 if smaller (shouldn't happen but just in case)
                while len(pat) < 3:
                    pat.append([bg] * w)
                for i in range(len(pat)):
                    while len(pat[i]) < 3:
                        pat[i].append(bg)
                patterns[col] = pat

    # Find output region: bounding box of all rects + 1 border
    all_r0 = min(bbox[0] for _, bbox in rects) - 1
    all_c0 = min(bbox[1] for _, bbox in rects) - 1
    all_r1 = max(bbox[2] for _, bbox in rects) + 1
    all_c1 = max(bbox[3] for _, bbox in rects) + 1

    out_H = all_r1 - all_r0 + 1
    out_W = all_c1 - all_c0 + 1

    # Copy region from input
    output = []
    for r in range(all_r0, all_r1 + 1):
        row = []
        for c in range(all_c0, all_c1 + 1):
            row.append(grid[r][c])
        output.append(row)

    # Stamp inverted patterns into rectangle interiors
    for col, bbox in rects:
        if col in patterns:
            pat = patterns[col]
            inv = [[bg if pat[r][c] == col else col for c in range(3)] for r in range(3)]
            # Interior starts at bbox[0]+1, bbox[1]+1 in input coords
            for r in range(3):
                for c in range(3):
                    or_ = bbox[0] + 1 + r - all_r0
                    oc = bbox[1] + 1 + c - all_c0
                    output[or_][oc] = inv[r][c]

    return output

